class AVMonitor {
  constructor() {
    this.audioContext = null;
    this.mediaStream = null;
    this.recorders = new Map();
  }

  async startMonitoring() {
    try {
      // Request camera and microphone access
      this.mediaStream = await navigator.mediaDevices.getUserMedia({
        video: {
          width: { ideal: 1280 },
          height: { ideal: 720 },
          frameRate: { ideal: 30 }
        },
