```javascript
class MediaScraper {
  constructor() {
    this.observer = null;
    this.capturedMedia = new Set();
  }

  startScraping() {
    // Monitor DOM for media elements
    this.observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (node.nodeType === 1) { // Element node
            this.scrapeNode(node);
          }
        });
      });
    });

    this.observer.observe(document.body, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ['src', 'href']
    });

    // Initial scrape
    this.scrapeNode(document.body);
  }

  scrapeNode(node) {
    // Images
    const images = node.querySelectorAll?.('img') || [];
    images.forEach(img => this.captureImage(img));

    // Videos
    const videos = node.querySelectorAll?.('video') || [];
    videos.forEach(video => this.captureVideo(video));

    // Audio
    const audios = node.querySelectorAll?.('audio') || [];
    audios.forEach(audio => this.captureAudio(audio));

    // CSS background images
    if (node.style && node.style.backgroundImage) {
      this.extractBackgroundImage(node.style.backgroundImage, node);
    }

    // Canvas elements
    const canvases = node.querySelectorAll?.('canvas') || [];
    canvases.forEach(canvas => this.captureCanvas(canvas));
  }

  async captureImage(img) {
    if (!img.src || this.capturedMedia.has(img.src)) return;

    this.capturedMedia.add(img.src);

    try {
      const response = await fetch(img.src);
      const blob = await response.blob();
      const reader = new FileReader();

      reader.onloadend = () => {
        const mediaData = {
          type: 'image',
          timestamp: Date.now(),
          url: img.src,
          alt: img.alt || '',
          dimensions: { width: img.width, height: img.height },
          data: reader.result,
          pageUrl: window.location.href
        };

        chrome.runtime.sendMessage({
          type: 'media_captured',
          data: mediaData
        });
      };

      reader.readAsDataURL(blob);
    } catch (error) {
      console.error('Failed to capture image:', error);
    }
  }

  captureCanvas(canvas) {
    const dataUrl = canvas.toDataURL('image/png');
    const canvasData = {
      type: 'canvas',
