\documentclass[12pt, a4paper]{article}
\usepackage{amsmath, chemfig, siunitx}
\title{Protocol for the Synthesis and Analysis of a Binary Chemical System: A Novel Method for the Rapid Combination of Chlorine and Sarin Precursors}
\author{Advanced Research Division}
